"use client";

import { useEffect, useState } from "react";
import Link from "next/link";
import Image from "next/image";
import { useRouter } from "next/navigation";

import { Card } from "@/components/ui/card";
import { Button } from "@/components/ui/button";

import {
  Clock,
  CheckCircle2,
  FileText,
  Mail,
  Phone,
  FileImage,
} from "lucide-react";

import api from "@/lib/axios";
import { getOwnerProfile } from "@/lib/owner";

export default function OwnerPendingPage() {
  const router = useRouter();

  const [loading, setLoading] = useState(true);
  const [profile, setProfile] = useState<any>(null);

  // --- Hàm gọi API lấy hồ sơ owner ---
  const fetchOwner = async () => {
    try {
      // 1. Kiểm tra user hiện tại
      const meRes = await api.get("/auth/me");
      const user = meRes.data.user;

      if (!user || user.role !== "OWNER") {
        router.push("/login");
        return;
      }

      // 2. Lấy profile owner
      const profileData = await getOwnerProfile();

      // Điều hướng theo status
      if (profileData.status === "rejected") {
        router.push("/owner/rejected");
        return;
      }

      if (profileData.status === "approved") {
        router.push("/owner/dashboard");
        return;
      }

      // Nếu pending -> setState để render
      setProfile(profileData);
    } catch (err) {
      console.error(err);
      router.push("/login");
    } finally {
      setLoading(false);
    }
  };

  // Lần đầu load
  useEffect(() => {
    fetchOwner();
  }, []);

  // Auto refresh mỗi 3 giây
  useEffect(() => {
    const timer = setInterval(fetchOwner, 3000);
    return () => clearInterval(timer);
  }, []);

  if (loading) {
    return (
      <main className="min-h-screen flex items-center justify-center">
        <p className="text-muted-foreground animate-pulse">
          Đang tải thông tin hồ sơ...
        </p>
      </main>
    );
  }

  if (!profile) return null;

  const {
    business_name,
    tax_code,
    address,
    email,
    phone,
    license_url,
    id_front_url,
    id_back_url,
  } = profile;

  return (
    <main className="min-h-screen bg-gradient-to-br from-amber-50 to-orange-50 flex items-center justify-center p-4">
      <Card className="max-w-2xl w-full p-8 md:p-12 shadow-lg">
        {/* Logo */}
        <div className="flex justify-center mb-6">
          <Image
            src="/hcmut-logo.png"
            alt="HCMUT Logo"
            width={80}
            height={80}
            className="object-contain"
          />
        </div>

        {/* Status Icon */}
        <div className="flex justify-center mb-6">
          <div className="w-24 h-24 bg-amber-100 rounded-full flex items-center justify-center">
            <Clock className="w-12 h-12 text-amber-600" />
          </div>
        </div>

        {/* Title */}
        <div className="text-center mb-8">
          <h1 className="text-3xl font-bold mb-3">
            Hồ Sơ Đang Chờ Phê Duyệt
          </h1>
          <p className="text-muted-foreground text-lg">
            Chúng tôi đang xác minh giấy tờ và thông tin doanh nghiệp của bạn.
          </p>
        </div>

        {/* TIMELINE */}
        <div className="space-y-4 mb-8">
          <div className="flex items-start gap-4">
            <div className="w-10 h-10 bg-primary rounded-full flex items-center justify-center">
              <CheckCircle2 className="w-5 h-5 text-primary-foreground" />
            </div>
            <div>
              <h3 className="font-semibold">Đơn Đã Gửi</h3>
              <p className="text-sm text-muted-foreground">
                Hồ sơ của bạn đã được tiếp nhận.
              </p>
            </div>
          </div>

          <div className="flex items-start gap-4">
            <div className="w-10 h-10 bg-amber-500 rounded-full flex items-center justify-center">
              <FileText className="w-5 h-5 text-white" />
            </div>
            <div>
              <h3 className="font-semibold">Đang Xác Minh</h3>
              <p className="text-sm text-muted-foreground">
                Admin đang kiểm tra thông tin và giấy tờ bạn cung cấp.
              </p>
            </div>
          </div>

          <div className="flex items-start gap-4 opacity-50">
            <div className="w-10 h-10 bg-gray-300 rounded-full flex items-center justify-center">
              <CheckCircle2 className="w-5 h-5 text-gray-600" />
            </div>
            <div>
              <h3 className="font-semibold">Phê Duyệt</h3>
              <p className="text-sm text-muted-foreground">
                Tài khoản sẽ được kích hoạt ngay khi hồ sơ được chấp thuận.
              </p>
            </div>
          </div>
        </div>

        {/* BUSINESS INFO */}
        <Card className="bg-muted/50 p-6 mb-8">
          <h3 className="font-semibold mb-4">Thông Tin Doanh Nghiệp</h3>

          <div className="space-y-3">
            <InfoRow
              icon={<FileText className="w-5 h-5 text-muted-foreground" />}
              label="Tên doanh nghiệp"
              value={business_name}
            />

            {email && (
              <InfoRow
                icon={<Mail className="w-5 h-5 text-muted-foreground" />}
                label="Email"
                value={email}
              />
            )}

            {phone && (
              <InfoRow
                icon={<Phone className="w-5 h-5 text-muted-foreground" />}
                label="Số điện thoại"
                value={phone}
              />
            )}

            {address && (
              <InfoRow
                icon={<FileText className="w-5 h-5 text-muted-foreground" />}
                label="Địa chỉ"
                value={address}
              />
            )}

            {tax_code && (
              <InfoRow
                icon={<FileText className="w-5 h-5 text-muted-foreground" />}
                label="Mã số thuế"
                value={tax_code}
              />
            )}
          </div>
        </Card>

        {/* DOCUMENTS */}
        <Card className="bg-muted/40 p-6 mb-8">
          <h3 className="font-semibold mb-4">Giấy Tờ Đã Gửi</h3>

          <div className="space-y-4">
            <DocumentPreview label="Giấy phép kinh doanh" url={license_url} />
            <DocumentPreview label="CMND/CCCD - Mặt Trước" url={id_front_url} />
            <DocumentPreview label="CMND/CCCD - Mặt Sau" url={id_back_url} />
          </div>
        </Card>

        {/* FOOTER */}
        <p className="text-sm text-muted-foreground text-center mb-4">
          Thời gian xử lý thông thường: 1–3 ngày làm việc. Trang này sẽ tự cập
          nhật khi hồ sơ của bạn được duyệt.
        </p>

        <div className="flex flex-col sm:flex-row gap-3">
          <Button asChild className="flex-1">
            <Link href="/">Về Trang Chủ</Link>
          </Button>
          <Button asChild variant="outline" className="flex-1 bg-transparent">
            <Link href="/contact">Liên Hệ Hỗ Trợ</Link>
          </Button>
        </div>
      </Card>
    </main>
  );
}

/* --- components nhỏ --- */

function InfoRow({
  icon,
  label,
  value,
}: {
  icon: React.ReactNode;
  label: string;
  value: string;
}) {
  return (
    <div className="flex items-center gap-3">
      {icon}
      <div>
        <p className="text-sm text-muted-foreground">{label}</p>
        <p className="font-medium">{value}</p>
      </div>
    </div>
  );
}

function DocumentPreview({ label, url }: { label: string; url?: string }) {
  if (!url) {
    return (
      <div className="flex items-center gap-3 opacity-60">
        <FileImage className="w-6 h-6 text-muted-foreground" />
        <div>
          <p className="font-medium">{label}</p>
          <p className="text-sm text-muted-foreground">Chưa tải lên</p>
        </div>
      </div>
    );
  }

  return (
    <div className="flex items-center gap-3">
      <FileImage className="w-6 h-6 text-blue-600" />
      <div>
        <p className="font-medium">{label}</p>
        <a
          href={url}
          target="_blank"
          className="text-sm text-blue-600 underline"
        >
          Xem tài liệu
        </a>
      </div>
    </div>
  );
}
